class BankAccount:
    def __init__(self, balance=0):
        self.balance = balance
    def deposit(self, amount):
        self.balance += amount
    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient funds")
            return
        self.balance -= amount

acc = BankAccount(1000)
acc.deposit(500)
print(acc.balance)
acc.withdraw(9999)
print(acc.balance)

