def relu(x):
    return max(0, x)

def neuron(inputs, weights, bias):
    total = sum(i * w for i, w in zip(inputs, weights)) + bias
    return relu(total)

print(neuron([1.0, 2.0], [0.5, 0.5], 0.0))
print(neuron([1.0, 2.0], [-1.0, -1.0], 0.0))

